Endpoint response section: GET /data-collections/ - List Data Collections
Response status: 200
Section label: schema
{
  "$schema": "http://json-schema.org/draft-04/schema#",
  "type": "array",
  "items": {
    "type": "object",
    "properties": {
      "displayName": {
        "type": "string",
        "description": "Name of the data collection"
      },
      "color": {
        "type": "string",
        "description": "Color of the data collection (using #RRGGBB syntax)"
      },
      "description": {
        "type": "string",
        "description": "The description of the data collection (markdown)"
      },
      "tags": {
        "type": "array",
        "description": "List of tags of the data collection"
      },
      "id": {
        "type": "string",
        "description": "Id of the data collection"
      },
      "itemCount": {
        "type": "number",
        "description": "Number of objects in the data collection"
      },
      "lastModifiedOn": {
        "type": "number",
        "description": "Timestamp of the last data-collection modification"
      }
    },
    "required": [
      "displayName",
      "color",
      "description",
      "tags",
      "id",
      "itemCount",
      "lastModifiedOn"
    ]
  }
}

