Endpoint request section: POST /data-collections/ - Create Data Collection
Section label: schema
{
  "$schema": "http://json-schema.org/draft-04/schema#",
  "type": "object",
  "properties": {
    "id": {
      "type": "string",
      "description": "Id of the Data Collection (a random id is generated if not provided)"
    },
    "displayName": {
      "type": "string",
      "description": "Name of the data collection"
    },
    "color": {
      "type": "string",
      "description": "Color of the data collection (using #RRGGBB syntax)"
    },
    "description": {
      "type": "string",
      "description": "The description of the data collection (markdown)"
    },
    "tags": {
      "type": "array",
      "description": "List of tags of the data collection"
    },
    "permissions": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "admin": {
            "type": "boolean",
            "description": "true if the permission grants administrator access"
          },
          "write": {
            "type": "boolean",
            "description": "true if the permission grants contributor access"
          },
          "read": {
            "type": "boolean",
            "description": "true if the permission grants member access"
          }
        },
        "oneOf": [
          {
            "properties": {
              "user": {
                "type": "string",
                "description": "Name of the user this permission applies to."
              }
            },
            "required": [
              "user"
            ]
          },
          {
            "properties": {
              "group": {
                "type": "string",
                "description": "Name of the group this permission applies to."
              }
            },
            "required": [
              "group"
            ]
          }
        ]
      },
      "description": "List of permissions of the data collection (READER, CONTRIBUTOR or ADMIN)"
    }
  },
  "required": [
    "displayName"
  ],
  "additionalProperties": false
}

